import React, { useState, useEffect } from "react";
import client from "../api/client";

const AdminCategories = () => {
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: "", description: "", icon: "" });

  useEffect(() => {
    loadCategories();
  }, []);

  const loadCategories = async () => {
    try {
      const { data } = await client.get("/categories/");
      setCategories(data);
      console.log("[AdminCategories] Loaded categories:", data.length);
    } catch (error) {
      console.error("[AdminCategories] Failed to load categories:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await client.post("/categories/", form);
      setForm({ name: "", description: "", icon: "" });
      setShowForm(false);
      loadCategories();
    } catch (error) {
      console.error("Failed to create category:", error);
      alert("Failed to create category");
    }
  };

  return (
    <div className="page">
      <div className="page-header-admin">
        <div>
          <div className="welcome-badge">📁 Category System</div>
          <h1 className="admin-title">Expense Categories</h1>
          <p className="admin-subtitle">Organize expenses with custom categories and budgets</p>
        </div>
        <button className="button" onClick={() => setShowForm(!showForm)}>
          {showForm ? "❌ Cancel" : "+ Create Category"}
        </button>
      </div>

      {showForm && (
        <div className="card" style={{ marginBottom: '24px' }}>
          <h3>Create New Category</h3>
          <form onSubmit={handleSubmit} className="form">
            <div className="field">
              <label>Category Name</label>
              <input
                type="text"
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                placeholder="e.g., Travel, Meals"
                required
              />
            </div>
            <div className="field">
              <label>Description</label>
              <input
                type="text"
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
                placeholder="e.g., Flight, train, taxi"
              />
            </div>
            <div className="field">
              <label>Icon (emoji)</label>
              <input
                type="text"
                value={form.icon}
                onChange={(e) => setForm({ ...form, icon: e.target.value })}
                placeholder="e.g., ✈️"
                maxLength="2"
              />
            </div>
            <button type="submit" className="button">Create Category</button>
          </form>
        </div>
      )}

      {loading ? (
        <div className="loading-state">Loading categories...</div>
      ) : (
        <div className="card">
          <table className="data-table">
            <thead>
              <tr>
                <th>Icon</th>
                <th>Name</th>
                <th>Description</th>
                <th>Status</th>
                <th>Created</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {categories.map(category => (
                <tr key={category.id}>
                  <td className="icon-cell">{category.icon || '📁'}</td>
                  <td><strong>{category.name}</strong></td>
                  <td>{category.description}</td>
                  <td>
                    <span className={`badge badge--${category.is_active ? 'success' : 'inactive'}`}>
                      {category.is_active ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>{new Date(category.created_at).toLocaleDateString()}</td>
                  <td>
                    <button className="btn-link">Edit</button>
                    <button className="btn-link">Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminCategories;
